// math.js — two named exports
export const PI = 3.14159;

export function add(a, b) {
  return a + b;
}

// Can also export at the bottom using a list:
const subtract = (a, b) => a - b;
const multiply = (a, b) => a * b;
export { subtract, multiply };

// app.js — import named exports by their exact names
import { PI, add, subtract } from './math.js';

console.log(PI);          // 3.14159
console.log(add(2, 3));   // 5

// Alias: rename on import
import { add as sum } from './math.js';
console.log(sum(2, 3));   // 5

// greet.js — one default export
export default function greet(name) {
  return `Hello, ${name}!`;
}

// Alternatively:
function greet(name) { return `Hello, ${name}!`; }
export default greet;

// app.js — import default export (no curly braces, any name)
import greet from './greet.js';
import sayHello from './greet.js'; // same module, different local name

console.log(greet('Alice'));    // Hello, Alice!
console.log(sayHello('Bob'));   // Hello, Bob!

// api.js
export const BASE_URL = 'https://api.example.com';
export const TIMEOUT = 5000;

export default async function fetchData(endpoint) {
  const res = await fetch(`${BASE_URL}${endpoint}`);
  return res.json();
}

// import both in one statement
import fetchData, { BASE_URL, TIMEOUT } from './api.js';
//     ^default    ^named exports

import * as MathUtils from './math.js';

console.log(MathUtils.PI);          // 3.14159
console.log(MathUtils.add(1, 2));   // 3

// The default export is accessible as MathUtils.default
console.log(MathUtils.default);     // the default export value

// Button.jsx
import { useState } from 'react'; // named import from react package

export const BUTTON_VARIANTS = ['primary', 'secondary', 'danger'];

export function useButtonState(initial = false) {
  return useState(initial);
}

export default function Button({ label, variant = 'primary', onClick }) {
  return (
    <button className={`btn btn-${variant}`} onClick={onClick}>
      {label}
    </button>
  );
}

// App.jsx
import Button, { BUTTON_VARIANTS, useButtonState } from './Button.jsx';

export default function App() {
  const [active, setActive] = useButtonState(false);
  return (
    <Button
      label={active ? 'On' : 'Off'}
      variant={BUTTON_VARIANTS[0]}
      onClick={() => setActive(v => !v)}
    />
  );
}

// components/index.js — barrel file
export { default as Button } from './Button.jsx';
export { default as Input } from './Input.jsx';
export { default as Modal } from './Modal.jsx';
export { BUTTON_VARIANTS } from './Button.jsx';

// Without barrel — verbose paths
import Button from './components/Button.jsx';
import Input from './components/Input.jsx';

// With barrel — clean single import
import { Button, Input, BUTTON_VARIANTS } from './components';

// Static import — resolved at parse time, always loaded
import { add } from './math.js';

// Dynamic import — loaded on demand, returns a Promise
async function loadChart() {
  const { Chart } = await import('./chart.js');
  return new Chart();
}

// React.lazy uses dynamic import internally:
// const LazyPage = React.lazy(() => import('./pages/Dashboard'));

// counter.js
export let count = 0;
export function increment() { count++; }

// main.js
import { count, increment } from './counter.js';

console.log(count); // 0
increment();
console.log(count); // 1 — live binding reflects the change

// However, you cannot re-assign the imported binding directly:
// count = 5; // TypeError: Assignment to constant variable

// greet.js exports a DEFAULT
export default function greet(name) { ... }

// WRONG — curly braces mean named import, but there's no named 'greet'
import { greet } from './greet.js'; // SyntaxError / undefined

// CORRECT — no curly braces for default
import greet from './greet.js';

// math.js exports NAMED symbols
export const PI = 3.14;

// WRONG — no curly braces imports the default (which doesn't exist)
import PI from './math.js'; // undefined

// CORRECT
import { PI } from './math.js';

// config.js — top-level await to fetch configuration at module initialisation
const response = await fetch('/api/config');
export const config = await response.json();

// Any module that imports config will wait for the fetch to complete
// before its own code runs.

// app.js
import { config } from './config.js';
// By the time this line runs, config is fully loaded
console.log(config.apiBase);

// src/hooks/index.js — barrel for hooks
export { default as useLocalStorage } from './useLocalStorage.js';
export { default as useDebounce } from './useDebounce.js';

// Usage elsewhere
import { useLocalStorage, useDebounce } from '../hooks';

// cart/cartUtils.js — pure functions, no React
export function calcTotal(items) {
  return items.reduce((sum, item) => sum + item.price * item.qty, 0);
}

export function applyDiscount(total, pct) {
  return total * (1 - pct / 100);
}

export const TAX_RATE = 0.08;

// cart/useCart.js — custom hook, depends on cartUtils
import { useState, useCallback } from 'react';
import { calcTotal, applyDiscount } from './cartUtils.js';

export default function useCart() {
  const [items, setItems] = useState([]);

  const addItem = useCallback((product) => {
    setItems((prev) => {
      const existing = prev.find((i) => i.id === product.id);
      if (existing) {
        return prev.map((i) =>
          i.id === product.id ? { ...i, qty: i.qty + 1 } : i
        );
      }
      return [...prev, { ...product, qty: 1 }];
    });
  }, []);

  const total = calcTotal(items);
  const discountedTotal = applyDiscount(total, 10);

  return { items, addItem, total, discountedTotal };
}

// cart/CartSummary.jsx — React component, depends on hook
import useCart from './useCart.js';
import { TAX_RATE } from './cartUtils.js';

export default function CartSummary() {
  const { items, total, discountedTotal } = useCart();
  const tax = discountedTotal * TAX_RATE;

  return (
    <div>
      <p>Items: {items.length}</p>
      <p>Subtotal: ${discountedTotal.toFixed(2)}</p>
      <p>Tax ({TAX_RATE * 100}%): ${tax.toFixed(2)}</p>
      <p>Total: ${(discountedTotal + tax).toFixed(2)}</p>
    </div>
  );
}

// vite.config.js — path alias configuration
import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';
import path from 'path';

export default defineConfig({
  plugins: [react()],
  resolve: {
    alias: {
      '@': path.resolve(__dirname, './src'),
    },
  },
});

// cartUtils.test.js
import { describe, it, expect } from 'vitest';
import { calcTotal, applyDiscount, TAX_RATE } from './cartUtils.js';

describe('calcTotal', () => {
  it('sums price × qty for all items', () => {
    const items = [
      { price: 10, qty: 2 },
      { price: 5, qty: 1 },
    ];
    expect(calcTotal(items)).toBe(25);
  });

  it('returns 0 for empty cart', () => {
    expect(calcTotal([])).toBe(0);
  });
});

describe('applyDiscount', () => {
  it('reduces total by the given percentage', () => {
    expect(applyDiscount(100, 10)).toBe(90);
  });
});
